DROP TABLE IF EXISTS `StudentMentalHealth`;
CREATE TABLE `StudentMentalHealth` (
  `Data ID` INT,
  `Data Set` INT,
  `Academic Performance` VARCHAR(1),
  `Absences` INT,
  `Age` INT,
  `Gender` VARCHAR(15),
  `Residence Status` VARCHAR(23),
  `Father Education Level` VARCHAR(18),
  `Father Job Category` VARCHAR(20),
  `Father Work Location` VARCHAR(23),
  `Mother Education Level` VARCHAR(18),
  `Mother Job Category` VARCHAR(20),
  `Mother Work Location` VARCHAR(23),
  `Sleeping Habit` VARCHAR(13),
  `Physical Activity` VARCHAR(3),
  `Organization Involvement` VARCHAR(3),
  `Extracurricular Involvement` VARCHAR(3),
  `Mental Health Status` VARCHAR(8)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;




